const { PrismaClient } = require('@prisma/client');
const p = new PrismaClient();

const codingQuestions = [
  // Lesson 9 - 1 missing coding question
  {lessonId:9,difficulty:"Medium",topic:"HTML5 APIs",title:"Web Storage Utility",problemStatement:"Build a storage utility that wraps localStorage/sessionStorage with JSON serialization, expiry support, and fallback to memory when storage is unavailable.",examples:"store.set('user', obj, 3600) stores for 1 hour. store.get('user') returns null if expired.",starterCodeJs:"const store = {\n  _mem: {},\n  _hasStorage: (() => { try { localStorage.setItem('_t','1'); localStorage.removeItem('_t'); return true; } catch(e) { return false; } })(),\n  set(key, value, ttl) {\n    const item = { v: value, exp: ttl ? Date.now() + ttl*1000 : null };\n    const str = JSON.stringify(item);\n    if (this._hasStorage) localStorage.setItem(key, str); else this._mem[key] = item;\n  },\n  get(key) {\n    let item;\n    if (this._hasStorage) { const raw = localStorage.getItem(key); if (!raw) return null; item = JSON.parse(raw); }\n    else item = this._mem[key];\n    if (!item) return null;\n    if (item.exp && Date.now() > item.exp) { this.remove(key); return null; }\n    return item.v;\n  },\n  remove(key) { if (this._hasStorage) localStorage.removeItem(key); else delete this._mem[key]; }\n};",hints:"TTL: store expiry as absolute timestamp. Compare Date.now() on get. Fallback to memory object if localStorage throws.",solutionExplanation:"Private/incognito mode may throw on localStorage. The try/catch feature detection handles this gracefully."},

  // Lesson 31 - React Fundamentals
  {lessonId:31,difficulty:"Easy",topic:"React Fundamentals",title:"First React Component",problemStatement:"Write a functional React component called UserCard that accepts name, email, and avatar props. It should show avatar image, name in h2, and email in a paragraph. Handle missing avatar with a placeholder.",examples:"<UserCard name='Alice' email='a@b.com' avatar='/img.jpg' />",starterCodeJs:"function UserCard({ name, email, avatar, role = 'User' }) {\n  return (\n    <div className='user-card'>\n      <img\n        src={avatar || `https://ui-avatars.com/api/?name=${encodeURIComponent(name)}`}\n        alt={`${name} avatar`}\n        className='user-card__avatar'\n      />\n      <div className='user-card__info'>\n        <h2 className='user-card__name'>{name}</h2>\n        <p className='user-card__email'>{email}</p>\n        <span className='user-card__role'>{role}</span>\n      </div>\n    </div>\n  );\n}",hints:"Default props with = in destructuring. Fallback avatar URL via || operator. alt text is required for accessibility.",solutionExplanation:"Functional components are plain functions returning JSX. Default prop values via destructuring defaults. Conditional rendering via || ."},
  {lessonId:31,difficulty:"Easy",topic:"React Fundamentals",title:"List Rendering with Keys",problemStatement:"Write a TodoList component that renders an array of todo items. Each item shows checkbox, text, and a delete button. Use stable IDs as keys.",examples:"<TodoList todos={[{id:1,text:'Buy milk',done:false}]} onToggle={fn} onDelete={fn} />",starterCodeJs:"function TodoList({ todos, onToggle, onDelete }) {\n  if (todos.length === 0) {\n    return <p className='empty'>No todos yet!</p>;\n  }\n  return (\n    <ul className='todo-list'>\n      {todos.map(todo => (\n        <li key={todo.id} className={`todo-item ${todo.done ? 'done' : ''}`}>\n          <input\n            type='checkbox'\n            checked={todo.done}\n            onChange={() => onToggle(todo.id)}\n          />\n          <span className='todo-text'>{todo.text}</span>\n          <button onClick={() => onDelete(todo.id)}>Delete</button>\n        </li>\n      ))}\n    </ul>\n  );\n}",hints:"key={todo.id} must be on the outermost element in the map. Use stable IDs not array index. Empty state is good UX.",solutionExplanation:"key helps React track items during reconciliation. Never use array index as key for lists that can reorder or change."},
  {lessonId:31,difficulty:"Medium",topic:"React Fundamentals",title:"Controlled Form",problemStatement:"Build a controlled signup form with email, password, and confirm password fields. Validate in real-time and show errors. Submit should be disabled until valid.",examples:"onChange syncs to state. Errors shown inline. Submit disabled while invalid.",starterCodeJs:"import { useState } from 'react';\nfunction SignupForm({ onSubmit }) {\n  const [form, setForm] = useState({ email:'', password:'', confirm:'' });\n  const [touched, setTouched] = useState({});\n  const errors = {\n    email: !/^[^@]+@[^@]+/.test(form.email) ? 'Valid email required' : '',\n    password: form.password.length < 8 ? 'Min 8 characters' : '',\n    confirm: form.confirm !== form.password ? 'Passwords must match' : ''\n  };\n  const isValid = !Object.values(errors).some(Boolean);\n  const update = field => e => setForm(f => ({ ...f, [field]: e.target.value }));\n  const blur = field => () => setTouched(t => ({ ...t, [field]: true }));\n  return (\n    <form onSubmit={e => { e.preventDefault(); if (isValid) onSubmit(form); }}>\n      {['email','password','confirm'].map(field => (\n        <div key={field}>\n          <input type={field === 'email' ? 'email' : 'password'}\n            value={form[field]} onChange={update(field)} onBlur={blur(field)}\n            placeholder={field} />\n          {touched[field] && errors[field] && <p className='error'>{errors[field]}</p>}\n        </div>\n      ))}\n      <button type='submit' disabled={!isValid}>Sign Up</button>\n    </form>\n  );\n}",hints:"touched tracks which fields the user has interacted with. Show errors only after blur. Compute validity from errors object.",solutionExplanation:"Controlled forms: value+onChange pairs. Validate on each render. Show errors only after user interaction (touched state)."},
  {lessonId:31,difficulty:"Medium",topic:"React Fundamentals",title:"Component Composition",problemStatement:"Build a Card component that accepts header, body, and footer as slot props. Also build a ProfileCard that composes Card with specific content.",examples:"<Card header={<h2>Title</h2>} body={<p>Content</p>} footer={<Button>Action</Button>} />",starterCodeJs:"function Card({ header, body, footer, className = '' }) {\n  return (\n    <div className={`card ${className}`}>\n      {header && <div className='card__header'>{header}</div>}\n      <div className='card__body'>{body}</div>\n      {footer && <div className='card__footer'>{footer}</div>}\n    </div>\n  );\n}\nfunction ProfileCard({ user }) {\n  return (\n    <Card\n      header={\n        <div className='profile-header'>\n          <img src={user.avatar} alt={user.name} />\n          <h3>{user.name}</h3>\n        </div>\n      }\n      body={<p>{user.bio}</p>}\n      footer={<a href={`mailto:${user.email}`}>Contact</a>}\n    />\n  );\n}",hints:"Slot props accept any JSX. Conditional rendering with && prevents empty divs for optional sections.",solutionExplanation:"Composition via props gives consumers full control over content. Avoids prop explosion compared to passing each content piece separately."},
  {lessonId:31,difficulty:"Hard",topic:"React Fundamentals",title:"Custom Select Component",problemStatement:"Build an accessible custom select/dropdown with keyboard navigation (arrow keys, Enter, Escape), ARIA attributes, and outside click to close.",examples:"Arrow up/down moves selection. Enter selects. Escape closes. Clicking outside closes.",starterCodeJs:"import { useState, useRef, useEffect } from 'react';\nfunction CustomSelect({ options, value, onChange, placeholder = 'Select...' }) {\n  const [open, setOpen] = useState(false);\n  const [focused, setFocused] = useState(-1);\n  const ref = useRef();\n  useEffect(() => {\n    const handler = e => { if (!ref.current.contains(e.target)) setOpen(false); };\n    document.addEventListener('mousedown', handler);\n    return () => document.removeEventListener('mousedown', handler);\n  }, []);\n  const selected = options.find(o => o.value === value);\n  const onKey = e => {\n    if (e.key === 'ArrowDown') { e.preventDefault(); setFocused(f => Math.min(f+1, options.length-1)); }\n    if (e.key === 'ArrowUp') { e.preventDefault(); setFocused(f => Math.max(f-1, 0)); }\n    if (e.key === 'Enter' && focused >= 0) { onChange(options[focused].value); setOpen(false); }\n    if (e.key === 'Escape') setOpen(false);\n    if (!open) setOpen(true);\n  };\n  return (\n    <div ref={ref} className='select' role='combobox' aria-expanded={open} onKeyDown={onKey} tabIndex={0}>\n      <div className='select__trigger' onClick={() => setOpen(o => !o)}>\n        {selected ? selected.label : placeholder}\n      </div>\n      {open && (\n        <ul className='select__menu' role='listbox'>\n          {options.map((opt, i) => (\n            <li key={opt.value} role='option' aria-selected={opt.value === value}\n              className={i === focused ? 'focused' : ''}\n              onClick={() => { onChange(opt.value); setOpen(false); }}>\n              {opt.label}\n            </li>\n          ))}\n        </ul>\n      )}\n    </div>\n  );\n}",hints:"role=combobox+listbox+option for ARIA. Track focused index separately from selected value. Cleanup event listener in useEffect return.",solutionExplanation:"Custom components need ARIA attributes to communicate state to screen readers. Keyboard navigation must match native select behavior."},
  {lessonId:31,difficulty:"Hard",topic:"React Fundamentals",title:"Data Table with Sort and Filter",problemStatement:"Build a DataTable component with sortable columns (click header to sort asc/desc) and a search filter. Should be generic enough to work with any array of objects.",examples:"<DataTable data={users} columns={['name','email','role']} searchKey='name' />",starterCodeJs:"import { useState, useMemo } from 'react';\nfunction DataTable({ data, columns, searchKey }) {\n  const [sortCol, setSortCol] = useState(null);\n  const [sortDir, setSortDir] = useState('asc');\n  const [search, setSearch] = useState('');\n  const displayed = useMemo(() => {\n    let rows = data.filter(row =>\n      !searchKey || !search || String(row[searchKey]).toLowerCase().includes(search.toLowerCase())\n    );\n    if (sortCol) rows = [...rows].sort((a,b) => {\n      const va = a[sortCol], vb = b[sortCol];\n      return (va < vb ? -1 : va > vb ? 1 : 0) * (sortDir === 'asc' ? 1 : -1);\n    });\n    return rows;\n  }, [data, search, searchKey, sortCol, sortDir]);\n  const handleSort = col => {\n    if (sortCol === col) setSortDir(d => d === 'asc' ? 'desc' : 'asc');\n    else { setSortCol(col); setSortDir('asc'); }\n  };\n  return (\n    <div>\n      {searchKey && <input value={search} onChange={e=>setSearch(e.target.value)} placeholder='Search...' />}\n      <table><thead><tr>\n        {columns.map(col => (\n          <th key={col} onClick={() => handleSort(col)} style={{cursor:'pointer'}}>\n            {col} {sortCol===col ? (sortDir==='asc' ? '↑' : '↓') : ''}\n          </th>\n        ))}\n      </tr></thead>\n      <tbody>{displayed.map((row,i) => (\n        <tr key={i}>{columns.map(col => <td key={col}>{row[col]}</td>)}</tr>\n      ))}</tbody></table>\n    </div>\n  );\n}",hints:"useMemo for filtered+sorted data prevents recomputation on unrelated renders. Toggle sortDir when clicking same column.",solutionExplanation:"useMemo with [data, search, sortCol, sortDir] deps recomputes only when those values change. Generic column config makes it reusable."},
  {lessonId:31,difficulty:"Easy",topic:"React Fundamentals",title:"Toggle Component",problemStatement:"Build a reusable Toggle switch component with accessible ARIA attributes. Accept checked, onChange, label, and disabled props.",examples:"<Toggle checked={dark} onChange={setDark} label='Dark mode' />",starterCodeJs:"function Toggle({ checked, onChange, label, disabled = false, id }) {\n  const toggleId = id || `toggle-${Math.random().toString(36).slice(2)}`;\n  return (\n    <label className={`toggle ${disabled ? 'disabled' : ''}`} htmlFor={toggleId}>\n      <input\n        id={toggleId}\n        type='checkbox'\n        role='switch'\n        checked={checked}\n        onChange={e => onChange(e.target.checked)}\n        disabled={disabled}\n        aria-checked={checked}\n        aria-label={label}\n      />\n      <span className='toggle__track'>\n        <span className='toggle__thumb' />\n      </span>\n      {label && <span className='toggle__label'>{label}</span>}\n    </label>\n  );\n}",hints:"role=switch is the ARIA role for toggle buttons. htmlFor links label to input for click area. aria-checked communicates state to screen readers.",solutionExplanation:"Using a real checkbox input (hidden with CSS) gives free keyboard support. role=switch + aria-checked communicate state to assistive tech."},
  {lessonId:31,difficulty:"Medium",topic:"React Fundamentals",title:"Pagination Component",problemStatement:"Build a Pagination component that shows page numbers with prev/next buttons. Handle edge cases: first/last page disabled, ellipsis for large page counts.",examples:"<Pagination page={3} total={50} perPage={10} onChange={setPage} />",starterCodeJs:"function Pagination({ page, total, perPage = 10, onChange }) {\n  const totalPages = Math.ceil(total / perPage);\n  const getPages = () => {\n    if (totalPages <= 7) return Array.from({length:totalPages},(_,i)=>i+1);\n    const pages = [1];\n    if (page > 3) pages.push('...');\n    for (let i = Math.max(2,page-1); i <= Math.min(totalPages-1,page+1); i++) pages.push(i);\n    if (page < totalPages-2) pages.push('...');\n    pages.push(totalPages);\n    return pages;\n  };\n  return (\n    <nav aria-label='Pagination'>\n      <button onClick={()=>onChange(page-1)} disabled={page===1}>Prev</button>\n      {getPages().map((p,i) => p === '...'\n        ? <span key={`ellipsis-${i}`}>...</span>\n        : <button key={p} onClick={()=>onChange(p)} aria-current={p===page?'page':undefined}\n            style={{fontWeight:p===page?'bold':'normal'}}>{p}</button>\n      )}\n      <button onClick={()=>onChange(page+1)} disabled={page===totalPages}>Next</button>\n    </nav>\n  );\n}",hints:"Ellipsis replaces skipped pages. aria-current=page marks the active page. Disable prev on page 1, next on last page.",solutionExplanation:"The ellipsis algorithm shows: always first+last, 3 around current, and ellipsis for gaps. aria-label on nav and aria-current improve accessibility."},
  {lessonId:31,difficulty:"Hard",topic:"React Fundamentals",title:"Infinite Scroll",problemStatement:"Build an InfiniteScroll component that loads more items when the user scrolls near the bottom. Use IntersectionObserver on a sentinel element.",examples:"<InfiniteScroll loadMore={fetchPage} hasMore={hasMore}>items</InfiniteScroll>",starterCodeJs:"import { useRef, useEffect } from 'react';\nfunction InfiniteScroll({ children, loadMore, hasMore, loading, threshold = 0.1 }) {\n  const sentinelRef = useRef();\n  useEffect(() => {\n    if (!hasMore || loading) return;\n    const observer = new IntersectionObserver(\n      ([entry]) => { if (entry.isIntersecting) loadMore(); },\n      { threshold }\n    );\n    const el = sentinelRef.current;\n    if (el) observer.observe(el);\n    return () => { if (el) observer.unobserve(el); };\n  }, [hasMore, loading, loadMore, threshold]);\n  return (\n    <div>\n      {children}\n      {hasMore && <div ref={sentinelRef} style={{height:'1px'}} aria-hidden='true' />}\n      {loading && <div className='loading-spinner'>Loading...</div>}\n    </div>\n  );\n}",hints:"Sentinel div at bottom triggers IntersectionObserver. Re-observe when hasMore/loading change. Cleanup on unmount.",solutionExplanation:"Sentinel element approach: 1px div at list bottom observed by IntersectionObserver. Fires loadMore when sentinel enters viewport."},

  // Lesson 32 - React Hooks
  {lessonId:32,difficulty:"Easy",topic:"React Hooks",title:"useToggle Custom Hook",problemStatement:"Write a useToggle custom hook that manages a boolean value. Return [value, toggle, setTrue, setFalse].",examples:"const [open, toggle, show, hide] = useToggle(false)",starterCodeJs:"import { useState, useCallback } from 'react';\nfunction useToggle(initialValue = false) {\n  const [value, setValue] = useState(initialValue);\n  const toggle = useCallback(() => setValue(v => !v), []);\n  const setTrue = useCallback(() => setValue(true), []);\n  const setFalse = useCallback(() => setValue(false), []);\n  return [value, toggle, setTrue, setFalse];\n}\n// Usage\nfunction Modal() {\n  const [isOpen, toggle, open, close] = useToggle();\n  return (\n    <div>\n      <button onClick={open}>Open Modal</button>\n      {isOpen && <div className='modal'><button onClick={close}>Close</button></div>}\n    </div>\n  );\n}",hints:"useCallback ensures stable function references (important if passed to memoized children). Functional update form prevents stale closures.",solutionExplanation:"Custom hooks extract reusable stateful logic. useCallback with [] deps creates stable references that won't cause child re-renders."},
  {lessonId:32,difficulty:"Easy",topic:"React Hooks",title:"useLocalStorage Hook",problemStatement:"Write a useLocalStorage hook that syncs state with localStorage. Handle JSON serialization, SSR, and storage events from other tabs.",examples:"const [theme, setTheme] = useLocalStorage('theme', 'light')",starterCodeJs:"import { useState, useEffect, useCallback } from 'react';\nfunction useLocalStorage(key, initialValue) {\n  const [state, setState] = useState(() => {\n    try {\n      const item = typeof window !== 'undefined' ? localStorage.getItem(key) : null;\n      return item ? JSON.parse(item) : initialValue;\n    } catch { return initialValue; }\n  });\n  const setValue = useCallback(value => {\n    setState(prev => {\n      const next = typeof value === 'function' ? value(prev) : value;\n      try { localStorage.setItem(key, JSON.stringify(next)); } catch {}\n      return next;\n    });\n  }, [key]);\n  useEffect(() => {\n    const onStorage = e => { if (e.key === key) setState(e.newValue ? JSON.parse(e.newValue) : initialValue); };\n    window.addEventListener('storage', onStorage);\n    return () => window.removeEventListener('storage', onStorage);\n  }, [key, initialValue]);\n  return [state, setValue];\n}",hints:"Lazy useState initializer runs once. storage event fires in OTHER tabs when localStorage changes. SSR check prevents errors.",solutionExplanation:"Lazy initializer avoids reading localStorage on every render. Storage event enables cross-tab sync. Functional setter keeps referential stability."},
  {lessonId:32,difficulty:"Medium",topic:"React Hooks",title:"useFetch Hook",problemStatement:"Build a useFetch hook that fetches data from a URL, manages loading/error/data state, and supports AbortController cleanup.",examples:"const {data, loading, error} = useFetch('/api/users')",starterCodeJs:"import { useState, useEffect } from 'react';\nfunction useFetch(url, options = {}) {\n  const [state, setState] = useState({ data: null, loading: true, error: null });\n  useEffect(() => {\n    if (!url) return;\n    const controller = new AbortController();\n    setState({ data: null, loading: true, error: null });\n    fetch(url, { ...options, signal: controller.signal })\n      .then(res => { if (!res.ok) throw new Error(`HTTP ${res.status}`); return res.json(); })\n      .then(data => setState({ data, loading: false, error: null }))\n      .catch(err => {\n        if (err.name !== 'AbortError') setState({ data: null, loading: false, error: err.message });\n      });\n    return () => controller.abort();\n  }, [url]); // eslint-disable-line react-hooks/exhaustive-deps\n  return state;\n}",hints:"AbortController cleanup prevents setState on unmounted components. AbortError should be ignored (expected on cleanup). Ignore options in deps to avoid infinite loop.",solutionExplanation:"AbortController prevents race conditions: if URL changes before fetch resolves, the old fetch is cancelled. Ignore AbortError since it's intentional."},
  {lessonId:32,difficulty:"Medium",topic:"React Hooks",title:"useDebounce and useThrottle Hooks",problemStatement:"Build useDebounce and useThrottle hooks. Debounce delays value updates; throttle limits how often they update.",examples:"const debouncedSearch = useDebounce(searchTerm, 300)",starterCodeJs:"import { useState, useEffect, useRef, useCallback } from 'react';\nfunction useDebounce(value, delay) {\n  const [debounced, setDebounced] = useState(value);\n  useEffect(() => {\n    const timer = setTimeout(() => setDebounced(value), delay);\n    return () => clearTimeout(timer);\n  }, [value, delay]);\n  return debounced;\n}\nfunction useThrottle(value, limit) {\n  const [throttled, setThrottled] = useState(value);\n  const lastUpdate = useRef(0);\n  useEffect(() => {\n    const now = Date.now();\n    if (now - lastUpdate.current >= limit) {\n      setThrottled(value);\n      lastUpdate.current = now;\n    } else {\n      const timer = setTimeout(() => { setThrottled(value); lastUpdate.current = Date.now(); }, limit);\n      return () => clearTimeout(timer);\n    }\n  }, [value, limit]);\n  return throttled;\n}\nfunction SearchBar() {\n  const [input, setInput] = useState('');\n  const debounced = useDebounce(input, 300);\n  // fetch when debounced changes\n}",hints:"Debounce: clear and reset timer on each value change. Throttle: check elapsed time since last update.",solutionExplanation:"Debounce fires after user stops typing. Throttle fires at most every N ms. Both reduce expensive operations like API calls."},
  {lessonId:32,difficulty:"Medium",topic:"React Hooks",title:"useIntersectionObserver Hook",problemStatement:"Build a useIntersectionObserver hook that returns whether an element is in the viewport. Use it to trigger fade-in animations on scroll.",examples:"const [ref, inView] = useIntersectionObserver(). Apply animation class when inView.",starterCodeJs:"import { useState, useEffect, useRef } from 'react';\nfunction useIntersectionObserver(options = {}) {\n  const ref = useRef();\n  const [entry, setEntry] = useState(null);\n  useEffect(() => {\n    const el = ref.current;\n    if (!el) return;\n    const observer = new IntersectionObserver(([e]) => setEntry(e), { threshold: 0.1, ...options });\n    observer.observe(el);\n    return () => observer.disconnect();\n  }, [options.threshold, options.rootMargin]);\n  return [ref, entry?.isIntersecting ?? false, entry];\n}\nfunction AnimatedSection({ children }) {\n  const [ref, inView] = useIntersectionObserver();\n  return (\n    <section ref={ref} className={`section ${inView ? 'visible' : 'hidden'}`}>\n      {children}\n    </section>\n  );\n}",hints:"Return tuple [ref, isIntersecting, entry] for flexibility. Disconnect on cleanup. Spread options for threshold and rootMargin.",solutionExplanation:"Hook returns a ref to attach to the element and a boolean for intersection state. Cleanup disconnects observer on unmount."},
  {lessonId:32,difficulty:"Hard",topic:"React Hooks",title:"useReducer Shopping Cart",problemStatement:"Build a shopping cart using useReducer. Actions: ADD_ITEM, REMOVE_ITEM, UPDATE_QUANTITY, CLEAR_CART. Derive totals from state.",examples:"dispatch({type:'ADD_ITEM', payload:{id:1,name:'Book',price:12.99}})",starterCodeJs:"import { useReducer, useMemo } from 'react';\nconst cartReducer = (state, action) => {\n  switch (action.type) {\n    case 'ADD_ITEM': {\n      const exists = state.find(i => i.id === action.payload.id);\n      if (exists) return state.map(i => i.id === action.payload.id ? {...i, qty: i.qty+1} : i);\n      return [...state, {...action.payload, qty: 1}];\n    }\n    case 'REMOVE_ITEM': return state.filter(i => i.id !== action.payload.id);\n    case 'UPDATE_QUANTITY': return state.map(i => i.id === action.payload.id ? {...i, qty: Math.max(0, action.payload.qty)} : i).filter(i => i.qty > 0);\n    case 'CLEAR_CART': return [];\n    default: return state;\n  }\n};\nfunction useCart() {\n  const [items, dispatch] = useReducer(cartReducer, []);\n  const totals = useMemo(() => ({\n    itemCount: items.reduce((s,i) => s+i.qty, 0),\n    total: items.reduce((s,i) => s+i.price*i.qty, 0)\n  }), [items]);\n  return { items, totals, dispatch };\n}",hints:"useReducer for complex state with multiple related actions. useMemo derives totals without extra state. Functional updates avoid stale state.",solutionExplanation:"useReducer centralizes state transitions. Each action type is a named, predictable mutation. useMemo derives computed values."},
  {lessonId:32,difficulty:"Hard",topic:"React Hooks",title:"Context + useReducer State",problemStatement:"Build a global notification system using Context + useReducer. Support adding notifications with auto-dismiss and manual dismiss.",examples:"useNotifications().addNotification({type:'success', message:'Saved!'}) shows toast",starterCodeJs:"import { createContext, useContext, useReducer, useCallback } from 'react';\nconst NotifContext = createContext();\nconst reducer = (state, action) => {\n  switch (action.type) {\n    case 'ADD': return [...state, {...action.payload, id: Date.now()}];\n    case 'REMOVE': return state.filter(n => n.id !== action.payload.id);\n    default: return state;\n  }\n};\nexport function NotifProvider({ children }) {\n  const [notifications, dispatch] = useReducer(reducer, []);\n  const add = useCallback((notif) => {\n    const id = Date.now();\n    dispatch({ type:'ADD', payload:{...notif, id} });\n    if (notif.duration !== 0) {\n      setTimeout(() => dispatch({type:'REMOVE', payload:{id}}), notif.duration || 3000);\n    }\n  }, []);\n  const remove = useCallback(id => dispatch({type:'REMOVE', payload:{id}}), []);\n  return (\n    <NotifContext.Provider value={{notifications, add, remove}}>\n      {children}\n      <NotifContainer notifications={notifications} onRemove={remove} />\n    </NotifContext.Provider>\n  );\n}\nexport const useNotifications = () => useContext(NotifContext);\nfunction NotifContainer({ notifications, onRemove }) {\n  return (\n    <div className='notif-container'>\n      {notifications.map(n => (\n        <div key={n.id} className={`notif notif--${n.type}`}>\n          {n.message}\n          <button onClick={() => onRemove(n.id)}>x</button>\n        </div>\n      ))}\n    </div>\n  );\n}",hints:"Combine Context (sharing) with useReducer (complex state). useCallback stabilizes add/remove so consumers don't re-render needlessly.",solutionExplanation:"Context+useReducer is the built-in alternative to Redux. useCallback prevents infinite render loops when consumers use add in useEffect."},
  {lessonId:32,difficulty:"Easy",topic:"React Hooks",title:"usePrevious Hook",problemStatement:"Write a usePrevious hook that returns the previous value of any variable. Use it to animate transitions when a value changes.",examples:"const prevCount = usePrevious(count). Animate up if count > prevCount.",starterCodeJs:"import { useRef, useEffect } from 'react';\nfunction usePrevious(value) {\n  const ref = useRef();\n  useEffect(() => { ref.current = value; }); // runs after render, no deps = always\n  return ref.current; // returns value from BEFORE this render\n}\nfunction Counter() {\n  const [count, setCount] = React.useState(0);\n  const prevCount = usePrevious(count);\n  return (\n    <div>\n      <p>Current: {count} | Previous: {prevCount ?? 'N/A'}</p>\n      <p className={count > (prevCount||0) ? 'up' : 'down'}>\n        {count > (prevCount||0) ? '↑' : '↓'}\n      </p>\n      <button onClick={()=>setCount(c=>c+1)}>+</button>\n      <button onClick={()=>setCount(c=>c-1)}>-</button>\n    </div>\n  );\n}",hints:"useEffect without deps runs after every render. ref.current is set AFTER render. Reading it during render gives last render's value.",solutionExplanation:"useRef persists across renders without causing re-renders. The timing trick: effect updates ref after render, so reading during render gives previous value."},
  {lessonId:32,difficulty:"Hard",topic:"React Hooks",title:"useVirtualList Hook",problemStatement:"Build a useVirtualList hook that renders only visible items in a long list. Returns containerProps, wrapperProps, and virtualItems.",examples:"const {containerProps, wrapperProps, virtualItems} = useVirtualList({items, estimateSize:50})",starterCodeJs:"import { useState, useRef, useCallback, useMemo } from 'react';\nfunction useVirtualList({ items, estimateSize = 50, overscan = 5 }) {\n  const containerRef = useRef();\n  const [scrollTop, setScrollTop] = useState(0);\n  const [height, setHeight] = useState(500);\n  const onScroll = useCallback(e => setScrollTop(e.target.scrollTop), []);\n  const totalHeight = items.length * estimateSize;\n  const startIndex = Math.max(0, Math.floor(scrollTop / estimateSize) - overscan);\n  const endIndex = Math.min(items.length - 1, Math.floor((scrollTop + height) / estimateSize) + overscan);\n  const virtualItems = useMemo(() => \n    Array.from({length: endIndex - startIndex + 1}, (_, i) => ({\n      index: startIndex + i,\n      item: items[startIndex + i],\n      offsetTop: (startIndex + i) * estimateSize\n    })), [startIndex, endIndex, items, estimateSize]);\n  return {\n    containerProps: { ref: containerRef, onScroll, style: {overflowY:'auto', height} },\n    wrapperProps: { style: {height: totalHeight, position:'relative'} },\n    virtualItems\n  };\n}",hints:"totalHeight = items.length * itemHeight. Start/end index from scrollTop/height. Overscan renders a few extra items above/below visible area.",solutionExplanation:"Virtual lists render only visible items. Items use position:absolute with offsetTop. Total height spacer maintains correct scrollbar."},
  {lessonId:32,difficulty:"Medium",topic:"React Hooks",title:"useEventListener Hook",problemStatement:"Write a useEventListener hook that attaches and cleans up DOM event listeners. Support options object for capture/passive.",examples:"useEventListener('keydown', handler, window). Cleans up on unmount.",starterCodeJs:"import { useEffect, useRef } from 'react';\nfunction useEventListener(event, handler, element = window, options) {\n  const savedHandler = useRef(handler);\n  useEffect(() => { savedHandler.current = handler; }, [handler]);\n  useEffect(() => {\n    const el = element?.current || element;\n    if (!el?.addEventListener) return;\n    const listener = e => savedHandler.current(e);\n    el.addEventListener(event, listener, options);\n    return () => el.removeEventListener(event, listener, options);\n  }, [event, element, options]);\n}\nfunction KeyLogger() {\n  const [key, setKey] = React.useState('');\n  useEventListener('keydown', e => setKey(e.key));\n  return <p>Last key: {key}</p>;\n}",hints:"Ref trick: store handler in ref to avoid re-running the effect on every handler change. The listener calls ref.current(e) instead.",solutionExplanation:"The savedHandler ref pattern: effect only re-runs when event/element/options change, but always calls the latest handler. Prevents unnecessary re-subscriptions."},

  // Lesson 33 - State Management
  {lessonId:33,difficulty:"Easy",topic:"State Management",title:"Context Theme Provider",problemStatement:"Build a ThemeProvider with light/dark themes using Context. useTheme hook provides theme values and toggleTheme function.",examples:"const {theme, toggleTheme} = useTheme(). theme.colors.bg changes with dark mode.",starterCodeJs:"import { createContext, useContext, useState } from 'react';\nconst themes = {\n  light: { bg:'#ffffff', text:'#0f172a', surface:'#f8fafc', border:'#e2e8f0', primary:'#3b82f6' },\n  dark:  { bg:'#0f172a', text:'#f8fafc', surface:'#1e293b', border:'#334155', primary:'#60a5fa' }\n};\nconst ThemeCtx = createContext();\nfunction ThemeProvider({ children }) {\n  const [mode, setMode] = useState(() => localStorage.getItem('theme') || 'light');\n  const toggle = () => setMode(m => { const next = m==='light'?'dark':'light'; localStorage.setItem('theme',next); return next; });\n  return (\n    <ThemeCtx.Provider value={{ mode, theme: themes[mode], toggleTheme: toggle }}>\n      <div style={{ background: themes[mode].bg, color: themes[mode].text, minHeight:'100vh' }}>\n        {children}\n      </div>\n    </ThemeCtx.Provider>\n  );\n}\nconst useTheme = () => useContext(ThemeCtx);",hints:"Lazy useState initializer reads localStorage once on mount. Context value includes both the theme object and the toggle function.",solutionExplanation:"Theme context avoids prop drilling. Lazy initializer prevents reading localStorage on every render. CSS custom properties are an alternative approach."},
  {lessonId:33,difficulty:"Medium",topic:"State Management",title:"Zustand-style Store",problemStatement:"Implement a simple Zustand-like store using a custom hook. The store should be usable across components without Context.",examples:"const useCount = createStore(set => ({count:0, inc:()=>set(s=>({count:s.count+1}))}));",starterCodeJs:"import { useState, useEffect } from 'react';\nfunction createStore(initializer) {\n  let state;\n  const listeners = new Set();\n  const setState = (partial) => {\n    const next = typeof partial === 'function' ? partial(state) : partial;\n    state = { ...state, ...next };\n    listeners.forEach(fn => fn(state));\n  };\n  state = initializer(setState);\n  return function useStore(selector = s => s) {\n    const [selected, setSelected] = useState(() => selector(state));\n    useEffect(() => {\n      const handler = s => setSelected(selector(s));\n      listeners.add(handler);\n      return () => listeners.delete(handler);\n    }, [selector]);\n    return selected;\n  };\n}\nconst useCount = createStore(set => ({\n  count: 0,\n  inc: () => set(s => ({count: s.count+1})),\n  dec: () => set(s => ({count: s.count-1}))\n}));",hints:"Store is a closure with state, listeners Set, and setState. Each hook invocation subscribes to state changes via a listener.",solutionExplanation:"This is how Zustand works: module-level state + a Set of subscribers. No Context needed. selector enables subscribing to only part of state."},
  {lessonId:33,difficulty:"Medium",topic:"State Management",title:"Redux Toolkit Slice",problemStatement:"Create a Redux Toolkit slice for a blog with posts: addPost, removePost, updatePost, and async fetchPosts with loading/error states.",examples:"dispatch(addPost({title,body})). dispatch(fetchPosts()) hits API.",starterCodeJs:"import { createSlice, createAsyncThunk } from '@reduxjs/toolkit';\nexport const fetchPosts = createAsyncThunk('posts/fetch', async () => {\n  const res = await fetch('/api/posts');\n  if (!res.ok) throw new Error('Failed to fetch posts');\n  return res.json();\n});\nconst postsSlice = createSlice({\n  name: 'posts',\n  initialState: { items: [], loading: false, error: null },\n  reducers: {\n    addPost: (state, action) => { state.items.unshift({...action.payload, id: Date.now()}); },\n    removePost: (state, action) => { state.items = state.items.filter(p => p.id !== action.payload); },\n    updatePost: (state, action) => { const p = state.items.find(p=>p.id===action.payload.id); if(p) Object.assign(p, action.payload); }\n  },\n  extraReducers: builder => {\n    builder\n      .addCase(fetchPosts.pending, state => { state.loading = true; state.error = null; })\n      .addCase(fetchPosts.fulfilled, (state, action) => { state.loading = false; state.items = action.payload; })\n      .addCase(fetchPosts.rejected, (state, action) => { state.loading = false; state.error = action.error.message; });\n  }\n});\nexport const { addPost, removePost, updatePost } = postsSlice.actions;\nexport default postsSlice.reducer;",hints:"RTK uses Immer under the hood - you can mutate state directly in reducers. createAsyncThunk handles pending/fulfilled/rejected automatically.",solutionExplanation:"RTK slices collocate reducer, actions, and state shape. Immer enables mutable-looking code that produces immutable state."},
  {lessonId:33,difficulty:"Easy",topic:"State Management",title:"State Lifting Pattern",problemStatement:"Demonstrate state lifting: start with two sibling components that each manage their own temperature state. Lift state to parent so they sync.",examples:"FahrenheitInput and CelsiusInput both show the same temperature. Changing one updates the other.",starterCodeJs:"import { useState } from 'react';\nfunction TempInput({ scale, value, onChange }) {\n  return (\n    <label>\n      Temperature in {scale}:\n      <input type='number' value={value} onChange={e => onChange(e.target.value)} />\n    </label>\n  );\n}\nfunction TemperatureConverter() {\n  const [celsius, setCelsius] = useState('');\n  const [lastChanged, setLastChanged] = useState('c');\n  const fahrenheit = celsius !== '' ? (parseFloat(celsius) * 9/5 + 32).toFixed(1) : '';\n  const onCelsius = val => { setCelsius(val); setLastChanged('c'); };\n  const onFahrenheit = val => { setCelsius(val !== '' ? ((parseFloat(val)-32)*5/9).toFixed(1) : ''); setLastChanged('f'); };\n  return (\n    <div>\n      <TempInput scale='Celsius' value={celsius} onChange={onCelsius} />\n      <TempInput scale='Fahrenheit' value={fahrenheit} onChange={onFahrenheit} />\n    </div>\n  );\n}",hints:"Store only one canonical value (Celsius). Derive Fahrenheit. Converting on input change keeps both fields in sync.",solutionExplanation:"Lifting state: parent owns single source of truth. Children receive values and callbacks. Derived values are computed, not stored."},
  {lessonId:33,difficulty:"Hard",topic:"State Management",title:"Optimistic Updates",problemStatement:"Implement optimistic updates for a like button. Immediately update UI, make API call in background, rollback on failure.",examples:"Click like -> count+1 immediately -> POST /api/like -> on error count-1 + error message",starterCodeJs:"import { useState, useCallback } from 'react';\nfunction useLike(postId, initialLiked, initialCount) {\n  const [liked, setLiked] = useState(initialLiked);\n  const [count, setCount] = useState(initialCount);\n  const [error, setError] = useState(null);\n  const toggle = useCallback(async () => {\n    const prevLiked = liked;\n    const prevCount = count;\n    // Optimistic update\n    setLiked(!liked);\n    setCount(c => liked ? c-1 : c+1);\n    setError(null);\n    try {\n      await fetch(`/api/posts/${postId}/like`, {\n        method: liked ? 'DELETE' : 'POST'\n      });\n    } catch {\n      // Rollback on failure\n      setLiked(prevLiked);\n      setCount(prevCount);\n      setError('Failed to update like');\n    }\n  }, [liked, count, postId]);\n  return { liked, count, error, toggle };\n}",hints:"Capture previous state before optimistic update. Restore previous state in catch block. UI updates immediately, network is best-effort.",solutionExplanation:"Optimistic updates make UI feel instant. Store previous values before updating, restore them if API fails. React Query handles this pattern automatically."},
  {lessonId:33,difficulty:"Medium",topic:"State Management",title:"useQuery-like Hook",problemStatement:"Build a simple data fetching hook similar to React Query. Support caching by URL, loading state, and refetch on demand.",examples:"const {data, loading, error, refetch} = useQuery('/api/users')",starterCodeJs:"import { useState, useEffect, useCallback, useRef } from 'react';\nconst cache = new Map();\nfunction useQuery(url, options = {}) {\n  const { staleTime = 30000 } = options;\n  const [state, setState] = useState({ data: cache.get(url)?.data || null, loading: !cache.get(url), error: null });\n  const controllerRef = useRef();\n  const fetch_ = useCallback(async (force = false) => {\n    const cached = cache.get(url);\n    if (cached && !force && Date.now() - cached.time < staleTime) {\n      setState({ data: cached.data, loading: false, error: null });\n      return;\n    }\n    controllerRef.current?.abort();\n    controllerRef.current = new AbortController();\n    setState(s => ({ ...s, loading: true, error: null }));\n    try {\n      const res = await fetch(url, { signal: controllerRef.current.signal });\n      const data = await res.json();\n      cache.set(url, { data, time: Date.now() });\n      setState({ data, loading: false, error: null });\n    } catch(e) {\n      if (e.name !== 'AbortError') setState(s => ({...s, loading: false, error: e.message}));\n    }\n  }, [url, staleTime]);\n  useEffect(() => { fetch_(); return () => controllerRef.current?.abort(); }, [fetch_]);\n  return { ...state, refetch: () => fetch_(true) };\n}",hints:"Module-level cache Map persists across component mounts. staleTime prevents unnecessary refetches. AbortController cancels on unmount/URL change.",solutionExplanation:"This demonstrates React Query's core: cache by key, stale-while-revalidate, abort on cleanup. The real library adds much more (retries, devtools, invalidation)."},
  {lessonId:33,difficulty:"Hard",topic:"State Management",title:"Undo/Redo with useReducer",problemStatement:"Add undo/redo to a text editor using a history stack in useReducer state. Support Ctrl+Z and Ctrl+Y keyboard shortcuts.",examples:"type text -> Ctrl+Z reverts -> Ctrl+Y reapplies",starterCodeJs:"import { useReducer, useEffect } from 'react';\nconst historyReducer = (state, action) => {\n  switch (action.type) {\n    case 'SET': {\n      const { past, present } = state;\n      return { past:[...past, present], present:action.payload, future:[] };\n    }\n    case 'UNDO': {\n      if (!state.past.length) return state;\n      const previous = state.past[state.past.length-1];\n      return { past:state.past.slice(0,-1), present:previous, future:[state.present,...state.future] };\n    }\n    case 'REDO': {\n      if (!state.future.length) return state;\n      return { past:[...state.past, state.present], present:state.future[0], future:state.future.slice(1) };\n    }\n    default: return state;\n  }\n};\nfunction useUndoRedo(initial) {\n  const [state, dispatch] = useReducer(historyReducer, { past:[], present:initial, future:[] });\n  useEffect(() => {\n    const handler = e => {\n      if ((e.ctrlKey||e.metaKey) && e.key==='z') { e.preventDefault(); dispatch({type:'UNDO'}); }\n      if ((e.ctrlKey||e.metaKey) && e.key==='y') { e.preventDefault(); dispatch({type:'REDO'}); }\n    };\n    window.addEventListener('keydown', handler);\n    return () => window.removeEventListener('keydown', handler);\n  }, []);\n  return [state.present, v=>dispatch({type:'SET',payload:v}), ()=>dispatch({type:'UNDO'}), ()=>dispatch({type:'REDO'}), { canUndo:state.past.length>0, canRedo:state.future.length>0 }];\n}",hints:"History stack: past[], present, future[]. UNDO: pop past, push present to future. REDO: pop future, push present to past.",solutionExplanation:"The cursor/stack pattern: present is current state, past is undo history, future is redo history. SET clears the future (can't redo after new change)."},
  {lessonId:33,difficulty:"Easy",topic:"State Management",title:"Derived State Pattern",problemStatement:"Show the anti-pattern of syncing state and fix it. Build a UserList where filter, sort, and pagination are state but the displayed list is derived (not stored).",examples:"Derived: displayedUsers = useMemo(() => users.filter().sort().slice(), [users, filter, sort, page])",starterCodeJs:"import { useState, useMemo } from 'react';\nfunction UserList({ users }) {\n  const [filter, setFilter] = useState('');\n  const [sort, setSort] = useState('name');\n  const [page, setPage] = useState(1);\n  const perPage = 10;\n  // DERIVED state - not stored in useState\n  const filtered = useMemo(() =>\n    users.filter(u => u.name.toLowerCase().includes(filter.toLowerCase())),\n    [users, filter]);\n  const sorted = useMemo(() =>\n    [...filtered].sort((a,b) => a[sort] < b[sort] ? -1 : a[sort] > b[sort] ? 1 : 0),\n    [filtered, sort]);\n  const paginated = useMemo(() =>\n    sorted.slice((page-1)*perPage, page*perPage),\n    [sorted, page]);\n  return (\n    <div>\n      <input value={filter} onChange={e=>{setFilter(e.target.value);setPage(1);}} placeholder='Filter...' />\n      {paginated.map(u => <div key={u.id}>{u.name}</div>)}\n    </div>\n  );\n}",hints:"Never store derived values in useState. Compute them from source state with useMemo. Reset page when filter changes.",solutionExplanation:"Derived state anti-pattern: useState for filteredUsers causes sync bugs when base users change. useMemo derives correctly every time."},

  // Lesson 34 - React Routing
  {lessonId:34,difficulty:"Easy",topic:"React Router",title:"Basic Route Setup",problemStatement:"Set up React Router v6 with routes for: Home (/), About (/about), Users (/users), UserDetail (/users/:id), and a 404 Not Found page. Show navigation links.",examples:"<BrowserRouter><Routes><Route path='/' element={<Home/>}/></Routes></BrowserRouter>",starterCodeJs:"import { BrowserRouter, Routes, Route, Link, useParams, Navigate } from 'react-router-dom';\nfunction Nav() {\n  return <nav><Link to='/'>Home</Link> <Link to='/about'>About</Link> <Link to='/users'>Users</Link></nav>;\n}\nfunction UserDetail() {\n  const { id } = useParams();\n  return <h2>User #{id}</h2>;\n}\nfunction App() {\n  return (\n    <BrowserRouter>\n      <Nav />\n      <Routes>\n        <Route path='/' element={<Home />} />\n        <Route path='/about' element={<About />} />\n        <Route path='/users' element={<UserList />} />\n        <Route path='/users/:id' element={<UserDetail />} />\n        <Route path='*' element={<h1>404 Not Found</h1>} />\n      </Routes>\n    </BrowserRouter>\n  );\n}",hints:"path='*' catches all unmatched routes for 404. useParams() reads :id from URL. Link uses client-side navigation.",solutionExplanation:"Route path='*' is the wildcard catch-all. Routes matches the first matching route from top to bottom (no fall-through unlike v5 Switch)."},
  {lessonId:34,difficulty:"Medium",topic:"React Router",title:"Protected Routes",problemStatement:"Build a ProtectedRoute component that checks authentication and redirects to /login if not authenticated. Show how to pass redirect location for after-login return.",examples:"<ProtectedRoute element={<Dashboard/>}/> redirects to /login?from=/dashboard if not authed",starterCodeJs:"import { Navigate, useLocation } from 'react-router-dom';\nfunction useAuth() {\n  return { isAuthenticated: !!localStorage.getItem('token'), user: JSON.parse(localStorage.getItem('user')||'null') };\n}\nfunction ProtectedRoute({ element, redirectTo = '/login' }) {\n  const { isAuthenticated } = useAuth();\n  const location = useLocation();\n  if (!isAuthenticated) {\n    return <Navigate to={redirectTo} state={{ from: location }} replace />;\n  }\n  return element;\n}\nfunction Login() {\n  const location = useLocation();\n  const navigate = useNavigate();\n  const from = location.state?.from?.pathname || '/';\n  const handleLogin = async () => {\n    // ... authenticate ...\n    navigate(from, { replace: true }); // return to original destination\n  };\n  return <button onClick={handleLogin}>Login</button>;\n}",hints:"useLocation() gets current path. Pass location as state to Navigate. Login reads location.state.from to redirect back.",solutionExplanation:"Passing {from: location} in state preserves the intended destination. After login, navigate to from path with replace:true (no back to login)."},
  {lessonId:34,difficulty:"Medium",topic:"React Router",title:"Nested Routes with Outlet",problemStatement:"Build a dashboard layout using nested routes. The DashboardLayout renders a sidebar and <Outlet /> where child routes render.",examples:"/dashboard -> DashboardLayout with Overview. /dashboard/users -> same layout with UsersList.",starterCodeJs:"import { Outlet, NavLink, Routes, Route } from 'react-router-dom';\nfunction DashboardLayout() {\n  return (\n    <div className='dashboard'>\n      <aside className='sidebar'>\n        <nav>\n          <NavLink to='/dashboard' end className={({isActive})=>isActive?'active':''}>Overview</NavLink>\n          <NavLink to='/dashboard/users' className={({isActive})=>isActive?'active':''}>Users</NavLink>\n          <NavLink to='/dashboard/settings' className={({isActive})=>isActive?'active':''}>Settings</NavLink>\n        </nav>\n      </aside>\n      <main className='content'>\n        <Outlet />\n      </main>\n    </div>\n  );\n}\nfunction App() {\n  return (\n    <Routes>\n      <Route path='/dashboard' element={<DashboardLayout />}>\n        <Route index element={<Overview />} />\n        <Route path='users' element={<UsersList />} />\n        <Route path='settings' element={<Settings />} />\n      </Route>\n    </Routes>\n  );\n}",hints:"Outlet renders the matched child route. index route renders at the parent path. NavLink's isActive class shows active link.",solutionExplanation:"Nested Routes render child content inside parent's Outlet. Layout components wrap content consistently. NavLink autodetects active state."},
  {lessonId:34,difficulty:"Easy",topic:"React Router",title:"URL State with useSearchParams",problemStatement:"Use useSearchParams to manage filter, sort, and page state in the URL. This makes the state shareable and bookmarkable.",examples:"?filter=admin&sort=name&page=2 in URL. Back button restores previous filter.",starterCodeJs:"import { useSearchParams } from 'react-router-dom';\nfunction UserTable() {\n  const [params, setParams] = useSearchParams();\n  const filter = params.get('filter') || '';\n  const sort = params.get('sort') || 'name';\n  const page = parseInt(params.get('page') || '1', 10);\n  const setFilter = v => setParams(p => { p.set('filter', v); p.set('page', '1'); return p; });\n  const setSort = v => setParams(p => { p.set('sort', v); return p; });\n  const setPage = v => setParams(p => { p.set('page', String(v)); return p; });\n  return (\n    <div>\n      <input value={filter} onChange={e => setFilter(e.target.value)} placeholder='Filter...' />\n      <select value={sort} onChange={e => setSort(e.target.value)}>\n        <option value='name'>Name</option>\n        <option value='email'>Email</option>\n      </select>\n      {/* table renders here */}\n    </div>\n  );\n}",hints:"setParams with function form merges with existing params (not replace all). URL state is automatically persisted to browser history.",solutionExplanation:"URL state enables sharing, bookmarking, and browser history. setParams functional form preserves other params while updating the targeted one."},
  {lessonId:34,difficulty:"Hard",topic:"React Router",title:"Route-based Code Splitting",problemStatement:"Implement lazy loading for route components using React.lazy and Suspense. Add loading skeleton and error boundary for each route.",examples:"const Dashboard = lazy(()=>import('./Dashboard')). <Suspense fallback={<Skeleton/>}>",starterCodeJs:"import { lazy, Suspense, Component } from 'react';\nconst Home = lazy(() => import('./pages/Home'));\nconst Dashboard = lazy(() => import('./pages/Dashboard'));\nconst Profile = lazy(() => import('./pages/Profile'));\nfunction PageSkeleton() {\n  return <div className='skeleton' style={{height:'400px'}} />;\n}\nclass RouteErrorBoundary extends Component {\n  state = { error: null };\n  static getDerivedStateFromError(error) { return { error }; }\n  render() {\n    if (this.state.error) return <div>Failed to load page. <button onClick={()=>this.setState({error:null})}>Retry</button></div>;\n    return this.props.children;\n  }\n}\nfunction LazyRoute({ component: Comp }) {\n  return (\n    <RouteErrorBoundary>\n      <Suspense fallback={<PageSkeleton />}><Comp /></Suspense>\n    </RouteErrorBoundary>\n  );\n}",hints:"lazy() takes a function returning a dynamic import. Suspense shows fallback while loading. ErrorBoundary catches chunk load failures.",solutionExplanation:"Each lazy route creates a separate JS chunk loaded on demand. ErrorBoundary catches network failures during chunk loading."},
  {lessonId:34,difficulty:"Medium",topic:"React Router",title:"Router with Loader Data",problemStatement:"Use React Router v6 data APIs: define a loader for a UserDetail route that fetches user data. Access it with useLoaderData.",examples:"loader: async ({params}) => fetch('/api/users/'+params.id). Component: const user = useLoaderData()",starterCodeJs:"import { createBrowserRouter, RouterProvider, useLoaderData } from 'react-router-dom';\nasync function userLoader({ params }) {\n  const res = await fetch(`/api/users/${params.id}`);\n  if (!res.ok) throw new Response('User not found', { status: 404 });\n  return res.json();\n}\nfunction UserDetail() {\n  const user = useLoaderData();\n  return (\n    <div>\n      <h1>{user.name}</h1>\n      <p>{user.email}</p>\n    </div>\n  );\n}\nconst router = createBrowserRouter([\n  {\n    path: '/users/:id',\n    element: <UserDetail />,\n    loader: userLoader,\n    errorElement: <div>Error loading user</div>\n  }\n]);\nfunction App() { return <RouterProvider router={router} />; }",hints:"Loaders run before rendering - no loading state needed in component. Throwing Response with status triggers errorElement. Data available synchronously via useLoaderData.",solutionExplanation:"Data router loaders eliminate the useEffect+loading pattern. Data is fetched in parallel with other routes during navigation."},
  {lessonId:34,difficulty:"Hard",topic:"React Router",title:"Breadcrumb Navigation",problemStatement:"Build a breadcrumb component that automatically generates breadcrumbs from the current route path using useMatches.",examples:"/users/42/posts -> Home > Users > User #42 > Posts",starterCodeJs:"import { useMatches, Link } from 'react-router-dom';\nfunction Breadcrumbs() {\n  const matches = useMatches();\n  const crumbs = matches.filter(m => m.handle?.breadcrumb);\n  return (\n    <nav aria-label='Breadcrumb'>\n      <ol className='breadcrumbs'>\n        {crumbs.map((m, i) => (\n          <li key={m.id}>\n            {i < crumbs.length-1\n              ? <Link to={m.pathname}>{m.handle.breadcrumb(m.data)}</Link>\n              : <span aria-current='page'>{m.handle.breadcrumb(m.data)}</span>}\n          </li>\n        ))}\n      </ol>\n    </nav>\n  );\n}\n// Route definition:\nconst routes = [{ path:'/users/:id', element:<UserDetail/>, loader:userLoader,\n  handle: { breadcrumb: (data) => `User: ${data?.name || 'Loading...'}` }\n}];",hints:"useMatches returns all matched routes. handle.breadcrumb is a custom property per route. Last crumb is current page (aria-current=page).",solutionExplanation:"handle lets you attach metadata to routes. useMatches reads matched routes with their data. Breadcrumbs become declarative - defined on the route, not in components."},
  {lessonId:34,difficulty:"Easy",topic:"React Router",title:"useNavigate Programmatic Navigation",problemStatement:"Build a multi-step form wizard that programmatically navigates between steps. After final step submission, redirect to success page.",examples:"Step 1 -> Next -> /wizard/step-2. Final submit -> redirect to /success.",starterCodeJs:"import { useNavigate, useParams } from 'react-router-dom';\nconst STEPS = ['personal', 'address', 'payment', 'review'];\nfunction WizardStep() {\n  const { step } = useParams();\n  const navigate = useNavigate();\n  const index = STEPS.indexOf(step);\n  const goNext = () => {\n    if (index < STEPS.length-1) navigate(`/wizard/${STEPS[index+1]}`);\n    else navigate('/success', { state: { message: 'Order complete!' } });\n  };\n  const goBack = () => {\n    if (index > 0) navigate(-1); // browser back\n  };\n  return (\n    <div>\n      <p>Step {index+1} of {STEPS.length}: {step}</p>\n      <div className='step-content'>{/* form fields for step */}</div>\n      <button onClick={goBack} disabled={index===0}>Back</button>\n      <button onClick={goNext}>{index===STEPS.length-1?'Submit':'Next'}</button>\n    </div>\n  );\n}",hints:"navigate(-1) uses browser history back. navigate('/path', {state:{...}}) passes data to next route. useParams reads the step name.",solutionExplanation:"Programmatic navigation is used for wizard flows, post-submit redirects, and conditional routing. navigate(-1) uses real browser history."},
  {lessonId:34,difficulty:"Medium",topic:"React Router",title:"Scroll Restoration",problemStatement:"Implement scroll restoration in a React Router app. Scroll to top on route change. Preserve scroll position when using back button.",examples:"navigate to new route -> scroll to top. Press back -> restore previous scroll position.",starterCodeJs:"import { useEffect } from 'react';\nimport { useLocation } from 'react-router-dom';\nconst scrollPositions = new Map();\nfunction ScrollRestoration() {\n  const location = useLocation();\n  useEffect(() => {\n    const key = location.key;\n    // On location change: restore or scroll to top\n    const saved = scrollPositions.get(key);\n    if (saved !== undefined) {\n      window.scrollTo(0, saved);\n    } else {\n      window.scrollTo(0, 0);\n    }\n    // Save scroll position before leaving\n    const saveScroll = () => scrollPositions.set(key, window.scrollY);\n    window.addEventListener('scroll', saveScroll, { passive: true });\n    return () => window.removeEventListener('scroll', saveScroll);\n  }, [location.key]);\n  return null;\n}\n// Add to App: <ScrollRestoration />",hints:"location.key is unique per history entry. Save scroll position on scroll event. Restore on navigation using saved position.",solutionExplanation:"React Router v6's data router has built-in scroll restoration. This manual approach uses location.key to identify unique history entries."},
  {lessonId:34,difficulty:"Hard",topic:"React Router",title:"Route Transition Animations",problemStatement:"Add page transition animations to route changes using Framer Motion (or CSS classes). Fade out the old page and fade in the new one.",examples:"Route change -> old page fades out -> new page fades in using AnimatePresence",starterCodeJs:"import { AnimatePresence, motion } from 'framer-motion';\nimport { useLocation, Routes } from 'react-router-dom';\nconst pageVariants = {\n  initial: { opacity: 0, y: 20 },\n  animate: { opacity: 1, y: 0 },\n  exit: { opacity: 0, y: -20 }\n};\nfunction AnimatedRoutes() {\n  const location = useLocation();\n  return (\n    <AnimatePresence mode='wait' initial={false}>\n      <Routes location={location} key={location.pathname}>\n        <Route path='/' element={\n          <motion.div variants={pageVariants} initial='initial' animate='animate' exit='exit' transition={{duration:0.2}}>\n            <Home />\n          </motion.div>\n        } />\n      </Routes>\n    </AnimatePresence>\n  );\n}",hints:"AnimatePresence tracks entering/exiting components. key={location.pathname} tells React when to mount/unmount. mode='wait' completes exit before enter.",solutionExplanation:"AnimatePresence needs key to detect route changes (old vs new component). mode=wait prevents overlap - exit animation completes before entrance."},

  // Lesson 35 - React Performance
  {lessonId:35,difficulty:"Easy",topic:"React Performance",title:"React.memo with Custom Comparison",problemStatement:"Wrap an expensive UserRow component with React.memo. Add a custom comparison function that ignores createdAt (changes every render) to prevent unnecessary re-renders.",examples:"React.memo(UserRow, (prev,next) => prev.user.id===next.user.id && prev.user.name===next.user.name)",starterCodeJs:"import { memo, useCallback } from 'react';\nconst UserRow = memo(function UserRow({ user, onEdit, onDelete }) {\n  console.log('UserRow render:', user.id);\n  return (\n    <tr>\n      <td>{user.name}</td>\n      <td>{user.email}</td>\n      <td>{user.role}</td>\n      <td>\n        <button onClick={() => onEdit(user.id)}>Edit</button>\n        <button onClick={() => onDelete(user.id)}>Delete</button>\n      </td>\n    </tr>\n  );\n}, (prev, next) => {\n  // return true to skip re-render\n  return prev.user.id === next.user.id &&\n    prev.user.name === next.user.name &&\n    prev.user.email === next.user.email;\n});\n// In parent - MUST use useCallback for handlers\nconst handleEdit = useCallback(id => navigate(`/users/${id}/edit`), [navigate]);\nconst handleDelete = useCallback(id => deleteUser(id), [deleteUser]);",hints:"Custom comparison returns true to SKIP re-render. Must also use useCallback for passed functions - otherwise new function references always trigger render.",solutionExplanation:"React.memo's comparison function: return true = same (skip render). Pair with useCallback for handlers - without it, new function refs break memoization."},
  {lessonId:35,difficulty:"Medium",topic:"React Performance",title:"useMemo for Expensive Calculations",problemStatement:"Write a component that calculates statistics from a large dataset using useMemo. Show it only recalculates when the data changes, not on every render.",examples:"const stats = useMemo(() => computeStats(data), [data]). Changing filters doesn't recompute stats.",starterCodeJs:"import { useMemo, useState } from 'react';\nfunction computeStats(data) {\n  console.time('computeStats');\n  const result = {\n    count: data.length,\n    sum: data.reduce((s, n) => s + n.value, 0),\n    avg: 0,\n    min: Infinity,\n    max: -Infinity,\n    median: 0\n  };\n  result.avg = result.sum / result.count;\n  result.min = Math.min(...data.map(d => d.value));\n  result.max = Math.max(...data.map(d => d.value));\n  const sorted = [...data].sort((a,b) => a.value-b.value);\n  result.median = sorted[Math.floor(sorted.length/2)]?.value;\n  console.timeEnd('computeStats');\n  return result;\n}\nfunction Dashboard({ data }) {\n  const [theme, setTheme] = useState('light');\n  const stats = useMemo(() => computeStats(data), [data]);\n  // Changing theme doesn't re-run computeStats\n  return <div className={theme}><Stats {...stats} /></div>;\n}",hints:"useMemo runs computeStats only when data changes. Theme changes don't recompute. Always profile before memoizing - the cost may be negligible.",solutionExplanation:"useMemo is best for genuinely expensive computations with stable inputs. Overuse adds overhead. Measure with React DevTools Profiler first."},
  {lessonId:35,difficulty:"Medium",topic:"React Performance",title:"Windowing with react-window",problemStatement:"Implement a virtualized list of 10,000 users using react-window FixedSizeList. Add search filtering with correct item count.",examples:"<FixedSizeList height={600} itemCount={filtered.length} itemSize={60}> renders only visible rows",starterCodeJs:"import { FixedSizeList } from 'react-window';\nimport { useMemo, useState } from 'react';\nfunction UserListRow({ index, style, data }) {\n  const user = data[index];\n  return (\n    <div style={style} className='user-row'>\n      <img src={user.avatar} alt='' width={40} height={40} />\n      <span>{user.name}</span>\n      <span>{user.email}</span>\n    </div>\n  );\n}\nfunction VirtualUserList({ users }) {\n  const [search, setSearch] = useState('');\n  const filtered = useMemo(() =>\n    users.filter(u => u.name.toLowerCase().includes(search.toLowerCase())),\n    [users, search]);\n  return (\n    <div>\n      <input value={search} onChange={e=>setSearch(e.target.value)} placeholder='Search...' />\n      <FixedSizeList height={600} width='100%' itemCount={filtered.length} itemSize={60} itemData={filtered}>\n        {UserListRow}\n      </FixedSizeList>\n    </div>\n  );\n}",hints:"itemData passes filtered array to each row via data prop. style prop (position/height) must be applied to row for correct positioning.",solutionExplanation:"react-window renders only ~10 rows at a time regardless of list size. itemData passes external data to row renderer. style positions each row absolutely."},
  {lessonId:35,difficulty:"Hard",topic:"React Performance",title:"Concurrent Features Demo",problemStatement:"Demonstrate React 18 concurrent features: useTransition for tab switching, useDeferredValue for search, and startTransition for heavy renders.",examples:"Typing in search stays responsive while list filters. Tab switches don't block user input.",starterCodeJs:"import { useState, useTransition, useDeferredValue, memo } from 'react';\nconst HeavyList = memo(function HeavyList({ query }) {\n  const items = Array.from({length:5000}, (_,i) => `Item ${i}: ${query}`);\n  return <ul>{items.filter(i=>i.includes(query)).map(i=><li key={i}>{i}</li>)}</ul>;\n});\nfunction SearchWithDeferral() {\n  const [input, setInput] = useState('');\n  const deferred = useDeferredValue(input);\n  const stale = deferred !== input;\n  return (\n    <div>\n      <input value={input} onChange={e=>setInput(e.target.value)} placeholder='Search...' />\n      {stale && <span>Updating...</span>}\n      <div style={{opacity: stale ? 0.5 : 1}}><HeavyList query={deferred} /></div>\n    </div>\n  );\n}\nfunction TabWithTransition() {\n  const [tab, setTab] = useState('home');\n  const [isPending, startTransition] = useTransition();\n  const switchTab = t => startTransition(() => setTab(t));\n  return (\n    <div>\n      {['home','about','heavy'].map(t => <button key={t} onClick={()=>switchTab(t)} style={{opacity:isPending?0.5:1}}>{t}</button>)}\n      {isPending ? <span>Loading...</span> : <TabContent tab={tab} />}\n    </div>\n  );\n}",hints:"useDeferredValue lets input update immediately while list update is deferred. isPending shows that transition is in progress.",solutionExplanation:"useDeferredValue: input updates eagerly, deferred lags behind during heavy work. useTransition marks state updates as non-urgent."},
  {lessonId:35,difficulty:"Easy",topic:"React Performance",title:"Avoid Inline Objects and Functions",problemStatement:"Identify and fix common React performance anti-patterns: inline object props, inline functions in JSX, and style objects created on every render.",examples:"Bad: style={{color:'red'}} creates new object each render. Good: extract to const outside component.",starterCodeJs:"// BAD patterns:\nfunction BadComponent({ name, onClick }) {\n  return (\n    <div\n      style={{ color: 'red', fontSize: '16px' }}  // new object every render\n      onClick={() => console.log(name)}             // new function every render\n    >\n      <Child config={{ key: 'value' }} />           // new object every render\n    </div>\n  );\n}\n// GOOD patterns:\nconst styles = { color: 'red', fontSize: '16px' };  // outside component\nconst childConfig = { key: 'value' };                // outside component\nfunction GoodComponent({ name, onClick }) {\n  const handleClick = useCallback(() => console.log(name), [name]);\n  return (\n    <div style={styles} onClick={handleClick}>\n      <Child config={childConfig} />\n    </div>\n  );\n}",hints:"Inline objects/functions create new references on every render, breaking React.memo and useCallback deps checks.",solutionExplanation:"Stable references are key to memoization. Objects/functions created inline are always new. Extract constants outside or use useCallback/useMemo."},
  {lessonId:35,difficulty:"Medium",topic:"React Performance",title:"Bundle Analysis",problemStatement:"Write a script to analyze the React app bundle. Identify large dependencies and implement code splitting for the heaviest ones.",examples:"Import chart.js only on analytics page. Split admin routes from main bundle.",starterCodeJs:"// webpack-bundle-analyzer setup\n// package.json script:\nconst bundleAnalyzer = {\n  scripts: {\n    analyze: 'ANALYZE=true npm run build',\n    build: 'next build'\n  }\n};\n// Dynamic import for heavy libraries:\nasync function loadChart() {\n  const { Chart } = await import(/* webpackChunkName: 'chart' */ 'chart.js/auto');\n  return Chart;\n}\n// In component:\nimport { useState, useEffect } from 'react';\nfunction AnalyticsPage() {\n  const [ChartClass, setChart] = useState(null);\n  useEffect(() => { loadChart().then(setChart); }, []);\n  if (!ChartClass) return <div>Loading chart...</div>;\n  return <canvas ref={canvas => new ChartClass(canvas, { type:'line', data:{} })} />;\n}",hints:"webpackChunkName magic comment names the chunk. Load heavy libs dynamically on the routes that need them.",solutionExplanation:"Bundle splitting: keep initial JS small, load heavy dependencies on demand. Chart.js is ~200KB - splitting it can halve initial bundle."},
  {lessonId:35,difficulty:"Hard",topic:"React Performance",title:"React Profiler API",problemStatement:"Use the React Profiler component to measure render times and identify slow components. Build a wrapper that logs renders above a threshold.",examples:"<Profiler id='UserList' onRender={onRenderCallback}> logs renders >16ms",starterCodeJs:"import { Profiler, useState } from 'react';\nconst renderLogs = [];\nfunction onRender(id, phase, actualDuration, baseDuration, startTime, commitTime) {\n  if (actualDuration > 16) {\n    console.warn(`Slow render [${id}]: ${actualDuration.toFixed(1)}ms (${phase})`);\n  }\n  renderLogs.push({ id, phase, actualDuration, baseDuration, time: new Date().toISOString() });\n}\nfunction ProfilerWrapper({ id, children, threshold = 16 }) {\n  return (\n    <Profiler id={id} onRender={(id, phase, actual) => {\n      if (actual > threshold) console.warn(`Slow: ${id} ${actual.toFixed(1)}ms`);\n      onRender(...arguments);\n    }}>\n      {children}\n    </Profiler>\n  );\n}\nfunction App() {\n  return (\n    <ProfilerWrapper id='App'>\n      <ProfilerWrapper id='UserList'><UserList /></ProfilerWrapper>\n      <ProfilerWrapper id='Sidebar'><Sidebar /></ProfilerWrapper>\n    </ProfilerWrapper>\n  );\n}",hints:"Profiler onRender fires after every render with timing data. Nested Profilers measure subtrees independently. Only active in development by default.",solutionExplanation:"Profiler API reveals render times programmatically. Complement with React DevTools Profiler for visual flame graph analysis."},
  {lessonId:35,difficulty:"Medium",topic:"React Performance",title:"Image Optimization Component",problemStatement:"Build an OptimizedImage component that: lazy loads, shows a blur placeholder, handles load error, and avoids layout shift with explicit dimensions.",examples:"<OptimizedImage src='/img.jpg' width={800} height={600} alt='...' blurDataUrl={tiny}/>",starterCodeJs:"import { useState } from 'react';\nfunction OptimizedImage({ src, width, height, alt, blurDataUrl, className }) {\n  const [loaded, setLoaded] = useState(false);\n  const [error, setError] = useState(false);\n  return (\n    <div style={{ width, height, position:'relative', overflow:'hidden' }}>\n      {!loaded && !error && blurDataUrl && (\n        <img src={blurDataUrl} alt='' aria-hidden style={{ position:'absolute', inset:0, width:'100%', height:'100%', objectFit:'cover', filter:'blur(10px)', transform:'scale(1.1)' }} />\n      )}\n      {error\n        ? <div className='img-error' style={{width,height}}>Failed to load</div>\n        : <img\n            src={src}\n            width={width}\n            height={height}\n            alt={alt}\n            loading='lazy'\n            decoding='async'\n            onLoad={() => setLoaded(true)}\n            onError={() => setError(true)}\n            className={className}\n            style={{ opacity: loaded ? 1 : 0, transition:'opacity 0.3s' }}\n          />\n      }\n    </div>\n  );\n}",hints:"Explicit width/height prevents CLS. loading=lazy defers offscreen loads. Blur placeholder shows while real image loads. onLoad reveals it.",solutionExplanation:"CLS prevention: explicit dimensions reserve space. Blur placeholder uses tiny base64 image (10x10px). Fade transition on load is polished UX."},
  {lessonId:35,difficulty:"Easy",topic:"React Performance",title:"Memoization Decision Guide",problemStatement:"Write a guide function that returns whether to memoize based on: component re-render frequency, prop change frequency, render cost, and whether it has children.",examples:"shouldMemoize({renderFreq:'high', propChangeFreq:'low', renderCost:'high'}) -> true",starterCodeJs:"function shouldMemoize({ renderFreq, propChangeFreq, renderCost, hasChildren }) {\n  const score = [\n    renderFreq === 'high' ? 2 : 0,\n    propChangeFreq === 'low' ? 2 : 0,\n    renderCost === 'high' ? 3 : renderCost === 'medium' ? 1 : 0,\n    hasChildren ? 1 : 0\n  ].reduce((a,b)=>a+b,0);\n  return {\n    recommended: score >= 4,\n    score,\n    reasoning: [\n      renderFreq === 'high' && 'Component re-renders frequently (parent causes it)',\n      propChangeFreq === 'low' && 'Props rarely change (memoization will hit)',\n      renderCost === 'high' && 'Render is expensive (heavy computation or large tree)',\n      hasChildren && 'Has memoized children that would also re-render'\n    ].filter(Boolean)\n  };\n}",hints:"Memoization is only beneficial when: (1) component renders often AND (2) props rarely change AND (3) render is expensive. Meeting only 1-2 may not help.",solutionExplanation:"React.memo cost: shallow comparison on every parent render. Break even requires saved render cost > comparison cost. Profile first, optimize second."},

  // Lesson 36 - React Patterns
  {lessonId:36,difficulty:"Easy",topic:"React Patterns",title:"HOC withLoading",problemStatement:"Write a withLoading HOC that wraps a component and shows a spinner while loading prop is true. Preserve all other props.",examples:"const UserListWithLoading = withLoading(UserList). <UserListWithLoading loading={true} />",starterCodeJs:"import { memo } from 'react';\nfunction withLoading(Component, LoadingComponent = () => <div className='spinner'>Loading...</div>) {\n  const WithLoading = memo(({ loading, loadingProps, ...props }) => {\n    if (loading) return <LoadingComponent {...loadingProps} />;\n    return <Component {...props} />;\n  });\n  WithLoading.displayName = `withLoading(${Component.displayName || Component.name})`;\n  return WithLoading;\n}\nfunction withError(Component) {\n  return function WithError({ error, ...props }) {\n    if (error) return <div className='error'>{error.message || String(error)}</div>;\n    return <Component {...props} />;\n  };\n}",hints:"Spread ...props passes all remaining props to the wrapped component. displayName helps React DevTools show meaningful names.",solutionExplanation:"HOCs use spreading to pass-through all props. displayName set for debugging. Composition: withError(withLoading(UserList)) stacks behaviors."},
  {lessonId:36,difficulty:"Medium",topic:"React Patterns",title:"Compound Tabs Component",problemStatement:"Build a Tabs compound component using Context: Tabs, TabList, Tab, and TabPanel. State is shared implicitly via Context.",examples:"<Tabs><TabList><Tab id='a'>A</Tab></TabList><TabPanel id='a'>Content A</TabPanel></Tabs>",starterCodeJs:"import { createContext, useContext, useState } from 'react';\nconst TabsCtx = createContext();\nfunction Tabs({ children, defaultTab }) {\n  const [active, setActive] = useState(defaultTab);\n  return <TabsCtx.Provider value={{active, setActive}}>{children}</TabsCtx.Provider>;\n}\nfunction TabList({ children }) {\n  return <div role='tablist'>{children}</div>;\n}\nfunction Tab({ id, children }) {\n  const { active, setActive } = useContext(TabsCtx);\n  return (\n    <button\n      role='tab'\n      aria-selected={active===id}\n      aria-controls={`panel-${id}`}\n      id={`tab-${id}`}\n      onClick={() => setActive(id)}\n      className={active===id?'active':''}>\n      {children}\n    </button>\n  );\n}\nfunction TabPanel({ id, children }) {\n  const { active } = useContext(TabsCtx);\n  return active===id\n    ? <div role='tabpanel' id={`panel-${id}`} aria-labelledby={`tab-${id}`}>{children}</div>\n    : null;\n}\nTabs.TabList = TabList;\nTabs.Tab = Tab;\nTabs.TabPanel = TabPanel;",hints:"Context shares active state between Tab and TabPanel without prop drilling. ARIA attributes (tablist, tab, tabpanel) make it accessible.",solutionExplanation:"Compound components communicate via Context. Consumers get clean API: <Tabs.Tab> not props like tabIds={['a','b']}. ARIA linking requires matching ids."},
  {lessonId:36,difficulty:"Medium",topic:"React Patterns",title:"Render Props Data Provider",problemStatement:"Build a DataProvider component that fetches data and uses render props (or children as function) to share it. Support loading and error states.",examples:"<DataProvider url='/api/users'>{({data,loading,error}) => <UserList users={data}/>}</DataProvider>",starterCodeJs:"import { useState, useEffect } from 'react';\nfunction DataProvider({ url, children, render, fallback = null }) {\n  const [state, setState] = useState({ data: null, loading: true, error: null });\n  useEffect(() => {\n    let cancelled = false;\n    setState({ data: null, loading: true, error: null });\n    fetch(url)\n      .then(r => r.json())\n      .then(data => { if (!cancelled) setState({ data, loading: false, error: null }); })\n      .catch(e => { if (!cancelled) setState({ data: null, loading: false, error: e }); });\n    return () => { cancelled = true; };\n  }, [url]);\n  const renderFn = render || children;\n  if (typeof renderFn !== 'function') return fallback;\n  if (state.loading) return fallback || <div>Loading...</div>;\n  return renderFn(state);\n}",hints:"Support both render prop and children-as-function patterns. cancelled flag prevents setState on unmounted component.",solutionExplanation:"Render props share stateful logic without HOCs. Largely replaced by hooks but still useful for JSX-embedded conditional rendering."},
  {lessonId:36,difficulty:"Hard",topic:"React Patterns",title:"Headless Accordion",problemStatement:"Build a headless Accordion that provides behavior (open/close, keyboard nav, ARIA) but no styling. Consumers provide their own markup.",examples:"useAccordion hook returns items with getToggleProps and getPanelProps (aria attributes, handlers).",starterCodeJs:"import { useState, useCallback } from 'react';\nfunction useAccordion({ items, multi = false }) {\n  const [openItems, setOpenItems] = useState(new Set());\n  const toggle = useCallback(id => {\n    setOpenItems(prev => {\n      const next = new Set(multi ? prev : []);\n      if (prev.has(id)) next.delete(id); else next.add(id);\n      return next;\n    });\n  }, [multi]);\n  return items.map((item, i) => {\n    const isOpen = openItems.has(item.id);\n    return {\n      ...item,\n      isOpen,\n      getToggleProps: () => ({\n        onClick: () => toggle(item.id),\n        'aria-expanded': isOpen,\n        'aria-controls': `panel-${item.id}`,\n        id: `toggle-${item.id}`\n      }),\n      getPanelProps: () => ({\n        id: `panel-${item.id}`,\n        role: 'region',\n        'aria-labelledby': `toggle-${item.id}`,\n        hidden: !isOpen\n      })\n    };\n  });\n}",hints:"Headless: return prop-getters (functions that return props objects). Consumer applies these props to their own elements. Fully accessible, zero styling.",solutionExplanation:"Prop-getter pattern (getToggleProps()) bundles all necessary props. Consumer spreads them: <button {...getToggleProps()}>. ARIA attributes included automatically."},
  {lessonId:36,difficulty:"Easy",topic:"React Patterns",title:"Controlled vs Uncontrolled Modal",problemStatement:"Implement the same Modal in both controlled (parent owns open state) and uncontrolled (internal state, trigger inside) modes.",examples:"Controlled: <Modal open={isOpen} onClose={close}>. Uncontrolled: <Modal trigger={<button>Open</button>}>",starterCodeJs:"import { useState } from 'react';\nfunction Modal({ open: controlledOpen, onClose, trigger, children }) {\n  const [internalOpen, setInternalOpen] = useState(false);\n  const isControlled = controlledOpen !== undefined;\n  const isOpen = isControlled ? controlledOpen : internalOpen;\n  const close = isControlled ? onClose : () => setInternalOpen(false);\n  return (\n    <>\n      {trigger && !isControlled && (\n        <span onClick={() => setInternalOpen(true)}>{trigger}</span>\n      )}\n      {isOpen && (\n        <div className='modal-overlay' onClick={close}>\n          <div className='modal-content' onClick={e=>e.stopPropagation()}>\n            {children}\n            <button onClick={close}>Close</button>\n          </div>\n        </div>\n      )}\n    </>\n  );\n}",hints:"isControlled: check if open prop is provided (not undefined). Use either controlled or internal state based on mode. overlay click closes, content click stops propagation.",solutionExplanation:"The uncontrolled/controlled duality is used by MUI, Headless UI, etc. It lets simple use cases work out of the box while allowing full control when needed."},
  {lessonId:36,difficulty:"Medium",topic:"React Patterns",title:"Polymorphic Component",problemStatement:"Build a Text component that renders as different HTML elements based on an 'as' prop. Maintain TypeScript-like safety for valid elements.",examples:"<Text as='h1'>Heading</Text>. <Text as='p'>Paragraph</Text>. <Text as='label'>Label</Text>",starterCodeJs:"const validElements = new Set(['h1','h2','h3','h4','h5','h6','p','span','label','div','li','dt','dd','caption']);\nfunction Text({ as: Tag = 'p', children, className, ...props }) {\n  if (!validElements.has(Tag)) {\n    console.warn(`Text: '${Tag}' is not a valid element. Defaulting to 'p'.`);\n    Tag = 'p';\n  }\n  return <Tag className={`text ${className || ''}`} {...props}>{children}</Tag>;\n}\nfunction Button({ as: Tag = 'button', children, ...props }) {\n  return <Tag {...props}>{children}</Tag>;\n}\n// Renders <a> when href provided:\n// <Button as='a' href='/home'>Home</Button>",hints:"Store element type in a variable (Tag) and use it as JSX element. Validate allowed elements. Spread props enables passing href to anchor.",solutionExplanation:"Polymorphic 'as' prop is a popular pattern for design systems. Render different semantic elements without separate components."},
  {lessonId:36,difficulty:"Hard",topic:"React Patterns",title:"Portal and z-index Manager",problemStatement:"Build a Portal component for modals/tooltips + a z-index manager that auto-assigns appropriate z-index levels to avoid conflicts.",examples:"<Portal zLevel='modal'><Modal/></Portal> gets z-index:1000. <Portal zLevel='tooltip'> gets 1100.",starterCodeJs:"import { createPortal, useState, useEffect, useRef } from 'react';\nconst Z_LEVELS = { base: 0, dropdown: 100, sticky: 200, modal: 1000, popover: 1050, tooltip: 1100, toast: 1200 };\nconst activePortals = new Map();\nfunction Portal({ children, zLevel = 'base', id }) {\n  const elRef = useRef();\n  if (!elRef.current) {\n    elRef.current = document.createElement('div');\n    elRef.current.style.zIndex = Z_LEVELS[zLevel] || 0;\n    elRef.current.className = `portal portal--${zLevel}`;\n  }\n  useEffect(() => {\n    document.body.appendChild(elRef.current);\n    if (id) activePortals.set(id, elRef.current);\n    return () => {\n      document.body.removeChild(elRef.current);\n      if (id) activePortals.delete(id);\n    };\n  }, [id]);\n  return createPortal(children, elRef.current);\n}",hints:"createPortal(children, domNode) renders children inside domNode which can be anywhere in the DOM. Cleanup removes portal container on unmount.",solutionExplanation:"Portals break out of the React component tree visually. createPortal renders children into a DOM node outside the parent hierarchy. Critical for modals/tooltips."},
  {lessonId:36,difficulty:"Medium",topic:"React Patterns",title:"Error Boundary Component",problemStatement:"Build a React Error Boundary class component with retry capability. Display fallback UI with error details and a reset button.",examples:"<ErrorBoundary fallback={<ErrorFallback/>}><UnsafeComponent/></ErrorBoundary>",starterCodeJs:"import { Component } from 'react';\nclass ErrorBoundary extends Component {\n  state = { error: null, errorInfo: null, key: 0 };\n  static getDerivedStateFromError(error) { return { error }; }\n  componentDidCatch(error, info) {\n    this.setState({ errorInfo: info });\n    this.props.onError?.(error, info);\n    // In production: log to Sentry, etc.\n    console.error('ErrorBoundary caught:', error, info.componentStack);\n  }\n  reset = () => this.setState({ error: null, errorInfo: null, key: k => k + 1 });\n  render() {\n    if (this.state.error) {\n      const Fallback = this.props.fallback;\n      if (Fallback) return <Fallback error={this.state.error} reset={this.reset} />;\n      return (\n        <div className='error-boundary'>\n          <h2>Something went wrong</h2>\n          <pre>{this.state.error.message}</pre>\n          <button onClick={this.reset}>Try Again</button>\n        </div>\n      );\n    }\n    return <div key={this.state.key}>{this.props.children}</div>;\n  }\n}",hints:"getDerivedStateFromError is static - sets error state. componentDidCatch receives error and componentStack for logging. key increment resets the subtree.",solutionExplanation:"Error boundaries must be class components (no hook equivalent for componentDidCatch). key increment remounts child subtree for clean retry."},
  {lessonId:36,difficulty:"Easy",topic:"React Patterns",title:"Feature Flag Component",problemStatement:"Build a FeatureFlag component that conditionally renders children based on whether a feature flag is enabled. Support a/b testing percentage.",examples:"<Feature flag='new-checkout'>New UI</Feature>. Falls back to children otherwise.",starterCodeJs:"const flags = {\n  'new-checkout': { enabled: true, rollout: 100 },\n  'ai-search': { enabled: true, rollout: 50 },  // 50% of users\n  'beta-dashboard': { enabled: false }\n};\nfunction getUserBucket(userId) {\n  // Simple hash for consistent user bucketing\n  let hash = 0;\n  for (const c of String(userId)) hash = (hash * 31 + c.charCodeAt(0)) & 0xffffffff;\n  return Math.abs(hash) % 100;\n}\nfunction Feature({ flag, userId, fallback = null, children }) {\n  const config = flags[flag];\n  if (!config?.enabled) return fallback;\n  const rollout = config.rollout ?? 100;\n  if (userId && rollout < 100) {\n    const bucket = getUserBucket(userId);\n    if (bucket >= rollout) return fallback;\n  }\n  return children;\n}",hints:"Hash userId to a consistent 0-99 bucket. If bucket >= rollout%, show fallback. Same userId always gets same experience.",solutionExplanation:"Consistent hashing ensures the same user always sees the same variant. This enables reproducible A/B testing without session storage."},

  // Lesson 37 - Next.js
  {lessonId:37,difficulty:"Easy",topic:"Next.js",title:"App Router Page Component",problemStatement:"Create a Next.js 14 App Router page at /blog with: a Server Component that fetches posts, a loading.tsx skeleton, and an error.tsx boundary.",examples:"app/blog/page.tsx is a Server Component. app/blog/loading.tsx shows while loading.",starterCodeJs:"// app/blog/page.tsx (Server Component)\nasync function BlogPage() {\n  const posts = await fetch('https://jsonplaceholder.typicode.com/posts', {\n    next: { revalidate: 3600 } // ISR: revalidate every hour\n  }).then(r => r.json());\n  return (\n    <div>\n      <h1>Blog Posts</h1>\n      <ul>{posts.slice(0,10).map(p => <li key={p.id}><a href={`/blog/${p.id}`}>{p.title}</a></li>)}</ul>\n    </div>\n  );\n}\nexport default BlogPage;\n// app/blog/loading.tsx\nfunction Loading() {\n  return <div className='skeleton'>{Array(5).fill(0).map((_,i)=><div key={i} className='skeleton-line'/>)}</div>;\n}\nexport default Loading;\n// app/blog/error.tsx\n'use client';\nfunction Error({ error, reset }) {\n  return <div><h2>Error: {error.message}</h2><button onClick={reset}>Retry</button></div>;\n}\nexport default Error;",hints:"Server Components can be async and fetch data directly. loading.tsx auto-wraps in Suspense. error.tsx must be 'use client' for reset function.",solutionExplanation:"App Router file conventions: page.tsx = route UI, loading.tsx = Suspense fallback, error.tsx = Error boundary. All auto-applied by Next.js."},
  {lessonId:37,difficulty:"Medium",topic:"Next.js",title:"Server Action Form",problemStatement:"Build a contact form using a Next.js Server Action. The form submits directly to the server action without an API route.",examples:"'use server' function handleContact(formData). <form action={handleContact}>",starterCodeJs:"'use server';\nimport { revalidatePath } from 'next/cache';\nimport { redirect } from 'next/navigation';\nasync function submitContact(formData) {\n  const data = {\n    name: formData.get('name'),\n    email: formData.get('email'),\n    message: formData.get('message')\n  };\n  if (!data.name || !data.email || !data.message) {\n    return { error: 'All fields required' };\n  }\n  await db.contact.create({ data });\n  revalidatePath('/contact');\n  redirect('/contact/success');\n}\n// app/contact/page.tsx\nfunction ContactPage() {\n  return (\n    <form action={submitContact}>\n      <input name='name' placeholder='Your name' required />\n      <input name='email' type='email' required />\n      <textarea name='message' required />\n      <button type='submit'>Send</button>\n    </form>\n  );\n}",hints:"'use server' marks the function as a Server Action. FormData is automatically passed. revalidatePath clears ISR cache. redirect goes to success page.",solutionExplanation:"Server Actions run on server. FormData is passed automatically. No API route needed. revalidatePath ensures the page shows updated data after mutation."},
  {lessonId:37,difficulty:"Medium",topic:"Next.js",title:"Dynamic Route with generateStaticParams",problemStatement:"Create a Next.js dynamic blog post page at /blog/[id]. Use generateStaticParams to pre-render the top 100 posts at build time.",examples:"export async function generateStaticParams() returns [{id:'1'},{id:'2'}...]",starterCodeJs:"// app/blog/[id]/page.tsx\nasync function getPost(id) {\n  const res = await fetch(`https://jsonplaceholder.typicode.com/posts/${id}`, {\n    next: { revalidate: 3600 }\n  });\n  if (!res.ok) return null;\n  return res.json();\n}\nexport async function generateStaticParams() {\n  const posts = await fetch('https://jsonplaceholder.typicode.com/posts').then(r=>r.json());\n  return posts.slice(0,100).map(p => ({ id: String(p.id) }));\n}\nexport async function generateMetadata({ params }) {\n  const post = await getPost(params.id);\n  return { title: post?.title || 'Blog Post', description: post?.body?.slice(0,160) };\n}\ntype Props = { params: { id: string } };\nexport default async function BlogPost({ params }: Props) {\n  const post = await getPost(params.id);\n  if (!post) notFound();\n  return <article><h1>{post.title}</h1><p>{post.body}</p></article>;\n}",hints:"generateStaticParams returns array of param objects. generateMetadata is a special export for SEO. notFound() triggers 404.",solutionExplanation:"generateStaticParams pre-renders at build time. At runtime, new IDs are rendered on-demand (dynamicParams:true by default) and cached."},
  {lessonId:37,difficulty:"Hard",topic:"Next.js",title:"Route Handler API Endpoint",problemStatement:"Create a Next.js Route Handler at /api/users that supports GET (list users with pagination) and POST (create user). Include proper error handling.",examples:"GET /api/users?page=1&limit=10. POST /api/users with {name,email} body.",starterCodeJs:"// app/api/users/route.ts\nimport { NextRequest, NextResponse } from 'next/server';\nexport async function GET(request) {\n  const { searchParams } = new URL(request.url);\n  const page = parseInt(searchParams.get('page') || '1');\n  const limit = Math.min(parseInt(searchParams.get('limit') || '10'), 100);\n  try {\n    const [users, total] = await Promise.all([\n      db.user.findMany({ skip: (page-1)*limit, take: limit, orderBy:{createdAt:'desc'} }),\n      db.user.count()\n    ]);\n    return NextResponse.json({ users, page, limit, total, pages: Math.ceil(total/limit) });\n  } catch(e) {\n    return NextResponse.json({ error: 'Failed to fetch users' }, { status: 500 });\n  }\n}\nexport async function POST(request) {\n  try {\n    const body = await request.json();\n    if (!body.name || !body.email) return NextResponse.json({ error: 'Name and email required' }, { status: 400 });\n    const user = await db.user.create({ data: { name: body.name, email: body.email } });\n    return NextResponse.json(user, { status: 201 });\n  } catch(e) {\n    if (e.code === 'P2002') return NextResponse.json({ error: 'Email already exists' }, { status: 409 });\n    return NextResponse.json({ error: 'Server error' }, { status: 500 });\n  }\n}",hints:"Export named functions GET, POST, etc. NextRequest.url for query params. NextResponse.json() with status option. Limit cap prevents abuse.",solutionExplanation:"Route handlers replace pages/api. Export named HTTP methods. NextResponse.json handles Content-Type header. Prisma P2002 is unique constraint violation."},
  {lessonId:37,difficulty:"Easy",topic:"Next.js",title:"Metadata and SEO",problemStatement:"Set up dynamic SEO metadata for a Next.js 14 app: global defaults, page-specific overrides, and Open Graph tags for blog posts.",examples:"export const metadata for static. export async function generateMetadata for dynamic.",starterCodeJs:"// app/layout.tsx - global defaults\nexport const metadata = {\n  metadataBase: new URL('https://mysite.com'),\n  title: { template: '%s | My Site', default: 'My Site' },\n  description: 'A great website built with Next.js',\n  openGraph: {\n    type: 'website',\n    locale: 'en_US',\n    url: 'https://mysite.com',\n    siteName: 'My Site'\n  },\n  twitter: { card: 'summary_large_image', site: '@mysite' }\n};\n// app/blog/[id]/page.tsx - dynamic metadata\nexport async function generateMetadata({ params }) {\n  const post = await getPost(params.id);\n  if (!post) return { title: 'Post Not Found' };\n  return {\n    title: post.title,\n    description: post.excerpt,\n    openGraph: {\n      title: post.title,\n      description: post.excerpt,\n      images: [{ url: post.image, width: 1200, height: 630 }]\n    }\n  };\n}",hints:"metadataBase needed for resolving relative URLs in OG images. title.template adds site name suffix. generateMetadata is async for dynamic data.",solutionExplanation:"title.template: 'Post Title | My Site' is auto-constructed. metadataBase resolves relative image URLs. generateMetadata deduplicates data fetching with React cache()."},
  {lessonId:37,difficulty:"Medium",topic:"Next.js",title:"Client Component with Server Data",problemStatement:"Build a pattern where a Server Component fetches data and passes it to a Client Component for interactivity. Show the boundary correctly.",examples:"Server Component fetches users -> passes to Client Component that handles filtering/selection.",starterCodeJs:"// app/users/page.tsx - Server Component\nasync function UsersPage() {\n  const users = await db.user.findMany({ orderBy: { name: 'asc' } });\n  // Pass serializable data (not DB objects) to client\n  const userData = users.map(u => ({ id: u.id, name: u.name, email: u.email }));\n  return <UserSelector initialUsers={userData} />;\n}\nexport default UsersPage;\n// components/UserSelector.tsx - Client Component\n'use client';\nimport { useState } from 'react';\nfunction UserSelector({ initialUsers }) {\n  const [search, setSearch] = useState('');\n  const [selected, setSelected] = useState(new Set());\n  const filtered = initialUsers.filter(u => u.name.toLowerCase().includes(search.toLowerCase()));\n  return (\n    <div>\n      <input value={search} onChange={e=>setSearch(e.target.value)} placeholder='Search users...' />\n      {filtered.map(u => (\n        <label key={u.id}>\n          <input type='checkbox' checked={selected.has(u.id)} onChange={()=>setSelected(s=>{const n=new Set(s);n.has(u.id)?n.delete(u.id):n.add(u.id);return n;})} />\n          {u.name}\n        </label>\n      ))}\n    </div>\n  );\n}",hints:"Server Component can be async and use db directly. Pass only plain serializable objects to Client Components (not Prisma model instances).",solutionExplanation:"Server-to-client data handoff: fetch in server component, pass serializable props to 'use client' components. Client adds interactivity on top."},
  {lessonId:37,difficulty:"Hard",topic:"Next.js",title:"Middleware for Auth",problemStatement:"Write Next.js middleware that checks authentication on protected routes. Redirect unauthenticated users to login. Allow public routes through.",examples:"middleware.ts matches /dashboard/* and /api/protected/*. Checks JWT in cookies.",starterCodeJs:"// middleware.ts\nimport { NextResponse } from 'next/server';\nimport { jwtVerify } from 'jose';\nexport const config = { matcher: ['/dashboard/:path*', '/api/protected/:path*'] };\nconst PUBLIC_ROUTES = ['/login', '/signup', '/api/auth'];\nexport async function middleware(request) {\n  const { pathname } = request.nextUrl;\n  if (PUBLIC_ROUTES.some(r => pathname.startsWith(r))) return NextResponse.next();\n  const token = request.cookies.get('auth-token')?.value;\n  if (!token) {\n    if (pathname.startsWith('/api/')) {\n      return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });\n    }\n    const url = new URL('/login', request.url);\n    url.searchParams.set('from', pathname);\n    return NextResponse.redirect(url);\n  }\n  try {\n    const { payload } = await jwtVerify(token, new TextEncoder().encode(process.env.JWT_SECRET));\n    const response = NextResponse.next();\n    response.headers.set('x-user-id', String(payload.sub));\n    return response;\n  } catch { return NextResponse.redirect(new URL('/login', request.url)); }\n}",hints:"config.matcher limits which routes trigger middleware. API routes should return 401 JSON, not redirect. Attach user info to request headers for downstream use.",solutionExplanation:"Middleware runs on Edge (fast). It can redirect, rewrite, or modify requests before they reach the route. Perfect for auth, i18n, A/B testing."}
];

async function main() {
  let ci = 0, cs = 0;
  for (const q of codingQuestions) {
    const exists = await p.practiceQuestion.findFirst({ where: { lessonId: q.lessonId, title: q.title } });
    if (!exists) { await p.practiceQuestion.create({ data: q }); ci++; } else cs++;
  }
  console.log(`Coding: ${ci} inserted, ${cs} skipped.`);
}

main().catch(console.error).finally(() => p.$disconnect());
